function CompatibilityRadar({
  dimensions,
}: {
  dimensions: BreedMatchResult["dimensions"]
}) {
  const size = 240
  const center = size / 2
  const maxRadius = 84
  const levels = [20, 40, 60, 80, 100]
  const axisCount = dimensions.length

  const polygonPoints = buildRadarPoints(
    dimensions.map((dimension) => dimension.score),
    center,
    maxRadius
  )

  return (
    <div className="mt-5 flex justify-center">
      <svg viewBox={`0 0 ${size} ${size}`} className="h-[240px] w-[240px]" role="img" aria-label="Radar de encaixe">
        {levels.map((level) => (
          <polygon
            key={level}
            points={buildRadarPoints(Array.from({ length: axisCount }, () => level), center, (maxRadius * level) / 100, true)}
            fill="none"
            stroke="rgba(148,163,184,0.22)"
            strokeWidth="1"
          />
        ))}

        {dimensions.map((dimension, index) => {
          const angle = getRadarAngle(index, axisCount)
          const x = center + Math.cos(angle) * maxRadius
          const y = center + Math.sin(angle) * maxRadius
          const labelX = center + Math.cos(angle) * (maxRadius + 22)
          const labelY = center + Math.sin(angle) * (maxRadius + 22)

          return (
            <g key={dimension.id}>
              <line x1={center} y1={center} x2={x} y2={y} stroke="rgba(148,163,184,0.22)" strokeWidth="1" />
              <text
                x={labelX}
                y={labelY}
                fill="rgba(226,232,240,0.9)"
                fontSize="11"
                textAnchor="middle"
                dominantBaseline="middle"
              >
                {dimension.label}
              </text>
            </g>
          )
        })}

        <polygon
          points={polygonPoints}
          fill="rgba(34,211,238,0.24)"
          stroke="rgba(16,185,129,0.95)"
          strokeWidth="2.5"
        />

        {dimensions.map((dimension, index) => {
          const angle = getRadarAngle(index, axisCount)
          const radius = (maxRadius * dimension.score) / 100
          const x = center + Math.cos(angle) * radius
          const y = center + Math.sin(angle) * radius

          return <circle key={`${dimension.id}-point`} cx={x} cy={y} r="4" fill="#22d3ee" />
        })}
      </svg>
    </div>
  )
}

function buildRadarPoints(values: number[], center: number, radius: number, uniform = false) {
  return values
    .map((value, index) => {
      const angle = getRadarAngle(index, values.length)
      const axisRadius = uniform ? radius : (radius * value) / 100
      const x = center + Math.cos(angle) * axisRadius
      const y = center + Math.sin(angle) * axisRadius
      return `${x},${y}`
    })
    .join(" ")
}

function getRadarAngle(index: number, total: number) {
  return -Math.PI / 2 + (index * Math.PI * 2) / total
}

function InsightPanel({ title, children }: { title: string; children: string }) {
  return (
    <div className="rounded-[24px] border border-white/10 bg-white/5 p-5">
      <p className="text-xs uppercase tracking-[0.2em] text-cyan-200/80">{title}</p>
      <p className="mt-3 whitespace-pre-wrap text-sm leading-7 text-slate-200">{children}</p>
    </div>
  )
}
